seen: set[str] = set()
parts: list[str] = []

src95 = Path("tests/test_push_95.py").read_text()
tree = ast.parse(src95)
import_lines = []
for node in tree.body:
    if isinstance(node, (ast.Import, ast.ImportFrom)):
        import_lines.extend(src95.splitlines()[node.lineno - 1 : node.end_lineno])
    elif isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef, ast.ClassDef)):
        break

HEADER = '"""Cross-module integration and API edge-case coverage."""\n\nfrom __future__ import annotations\n\n'
imports_block = "\n".join(import_lines) + "\n"

def should_skip(chunk: str) -> bool:
    return any(m in chunk for m in SCRAPE_MARKERS)

def chunks(source: str):
    tree = ast.parse(source)
    lines = source.splitlines(keepends=True)
    for node in tree.body:
        if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
            if node.name.startswith("test_"):
                yield node.name, "".join(lines[node.lineno - 1 : node.end_lineno])

for path in SOURCES:
